import{c as a,Q as t,j as r,m as n}from"./chunks/framework.BXc4yaFE.js";const m=JSON.parse('{"title":"Latent Space — 2026-04-29","description":"","frontmatter":{"title":"Latent Space — 2026-04-29","date":"2026-04-29T00:00:00.000Z","source":"Latent Space","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-04/2026-04-29-latent-space.md","filePath":"research/ai-news/2026-04/2026-04-29-latent-space.md","lastUpdated":1779894392000}'),s={name:"research/ai-news/2026-04/2026-04-29-latent-space.md"};function o(i,e,l,c,h,p){return t(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="🔬-latent-space-—-2026-04-29" tabindex="-1">🔬 Latent Space — 2026-04-29 <a class="header-anchor" href="#🔬-latent-space-—-2026-04-29" aria-label="Permalink to &quot;🔬 Latent Space — 2026-04-29&quot;">​</a></h1><blockquote><p>swyx 開發者簡報，未公開專案 + 工程視角 來源：<a href="https://www.latent.space/feed" target="_blank" rel="noreferrer">Latent Space</a></p></blockquote><hr><h2 id="ainews-not-much-happened-today" tabindex="-1"><a href="https://www.latent.space/p/ainews-not-much-happened-today" target="_blank" rel="noreferrer">[AINews] not much happened today</a> <a class="header-anchor" href="#ainews-not-much-happened-today" aria-label="Permalink to &quot;[[AINews] not much happened today](https://www.latent.space/p/ainews-not-much-happened-today)&quot;">​</a></h2><p><em>🔬 Latent Space | 2026-04-29</em></p><p>When we made the AINews → Substack move, we committed to having Matt Levine style op-eds every day, but some days there just isn’t much going on and we will just say so - we are working on small essays around inference demand and multiagents, but today is not that day.</p><p>Interesting model releases from <a href="https://x.com/NVIDIAAI/status/2049159441870717428?s=20" target="_blank" rel="noreferrer">Nvidia Nemotron</a>, <a href="https://x.com/poolsideai/status/2049144111626670282?s=20" target="_blank" rel="noreferrer">Poolside</a>, and <a href="https://x.com/status_effects/status/2048878495539843211" target="_blank" rel="noreferrer">Alec Radford</a>, but it’s unclear any of them will stand the test of time. <a href="https://x.com/sama/status/2049241518540808440?s=20" target="_blank" rel="noreferrer">GPT-6 hype</a> is beginning.</p><p>AI News for 4/27/2026-4/28/2026. We checked 12 subreddits, <a href="https://twitter.com/i/lists/1585430245762441216" target="_blank" rel="noreferrer">544 Twitters</a> and no further Discords. <a href="https://news.smol.ai/" target="_blank" rel="noreferrer">AINews’ website</a> lets you search all past issues. As a reminder, <a href="https://www.latent.space/p/2026" target="_blank" rel="noreferrer">AINews is now a section of Latent Space</a>. You can <a href="https://support.substack.com/hc/en-us/articles/8914938285204-How-do-I-subscribe-to-or-unsubscribe-from-a-section-on-Substack" target="_blank" rel="noreferrer">opt in/out</a> of email frequencies!</p><p>AI Twitter Recap</p><p>Inference Systems, vLLM 0.20, and the Hardware/Kernel Race Around DeepSeek V4</p><p>vLLM’s latest release is heavily about memory and MoE serving efficiency: <a href="https://x.com/TeksEdge/status/2048983564801450315" target="_blank" rel="noreferrer">vLLM v0.20.0</a> shipped with TurboQuant 2-bit KV cache for 4× KV capacity, FA4 re-enabled for MLA prefill on SM90+, a new vLLM IR foundation, fused RMSNorm for a reported 2.1% end-to-end latency improvement, plus support updates spanning DeepSeek V4 MegaMoE on Blackwell, Jetson Thor, ROCm, Intel XPU, and easier GB200/Grace-Blackwell setup. In parallel, <a href="https://x.com/SemiAnalysis_/status/2048957715955765284" target="_blank" rel="noreferrer">SemiAnalysis</a> highlighted early DeepSeek V4 Pro serving results on B200/B300/H200/GB200 disaggregated setups, claiming B300 can be up to 8× faster than H200 for this workload and pointing to upcoming vLLM 0.20 benchmarking with DeepGEMM MegaMoE, which fuses EP dispatch + EP combine + GEMMs + SwiGLU into a single mega-kernel.</p><p>DeepSeek support: several posts focused on serving tradeoffs: <a href="https://x.com/jeremyphoward/status/2049098509530583199" target="_blank" rel="noreferrer">Jeremy Howard noted DeepSeek V4’s support for prefill</a> as a capability many providers have dropped, while <a href="https://x.com/maharshii/status/2049058891389108640" target="_blank" rel="noreferrer">Maharshi</a> pointed out the overheads of dynamic activation quantization, arguing that static quantization often wins on inference speed despite calibration cost. There was also growing interest in alternate stack portability: <a href="https://x.com/teortaxesTex/status/2049185408785998217" target="_blank" rel="noreferrer">teortaxesTex argued DeepSeek is structurally moving away from CUDA lock-in via TileKernels</a>, suggesting model vendors may increasingly optimize for heterogeneous or domestic accelerator fleets rather than NVIDIA-only deployment.</p><p>Open Model Releases: Poolside Laguna XS.2, NVIDIA Nemotron 3 Nano Omni, and TRELLIS.2</p><p>Poolside made its first public model release with an unusually deployment-friendly open-weight coder: <a href="https://x.com/poolsideai/status/2049144111626670282" target="_blank" rel="noreferrer">@poolsideai announced Laguna XS.2</a>, a 33B total / 3B active MoE coding model trained fully in-house, released under Apache 2.0, and advertised as able to run on a single GPU. <a href="https://x.com/eisokant/status/2049142230397370537" target="_blank" rel="noreferrer">Poolside’s broader release</a> also included Laguna M.1 and an agent harness, emphasizing that the company trained from scratch on its own data, training infra, RL, and inference stack. Community summaries added more color: <a href="https://x.com/AymericRoucher/status/2049156715304935451" target="_blank" rel="noreferrer">Aymeric Roucher</a> described two coder models—225B/23B active and 33B/3B active—with hybrid attention, FP8 KV cache, and claimed performance near Qwen-3.5; <a href="https://x.com/ollama/status/2049184817603031463" target="_blank" rel="noreferrer">Ollama</a> shipped it immediately.</p><p>NVIDIA’s Nemotron 3 Nano Omni was the day’s biggest infra-native model launch: <a href="https://x.com/NVIDIAAI/status/2049159441870717428" target="_blank" rel="noreferrer">@NVIDIAAI introduced Nemotron 3 Nano Omni</a>, an open 30B / A3B multimodal MoE with 256K context built for agentic workloads spanning text, image, video, audio, and documents. Distribution was immediate across the stack: <a href="https://x.com/OpenRouter/status/2049164366218772526" target="_blank" rel="noreferrer">OpenRouter</a>, <a href="https://x.com/lmstudio/status/2049172192705864091" target="_blank" rel="noreferrer">LM Studio</a>, <a href="https://x.com/ollama/status/2049194377751437470" target="_blank" rel="noreferrer">Ollama</a>, <a href="https://x.com/UnslothAI/status/2049161390150365344" target="_blank" rel="noreferrer">Unsloth</a>, <a href="https://x.com/fal/status/2049160999442198632" target="_blank" rel="noreferrer">fal</a>, <a href="https://x.com/FireworksAI_HQ/status/2049159136802398546" target="_blank" rel="noreferrer">Fireworks</a>, <a href="https://x.com/DeepInfra/status/2049158141070524815" target="_blank" rel="noreferrer">DeepInfra</a>, <a href="https://x.com/togethercompute/status/2049160446708711883" target="_blank" rel="noreferrer">Together</a>, <a href="https://x.com/baseten/status/2049160818575749300" target="_blank" rel="noreferrer">Baseten</a>, <a href="https://x.com/Canonical/status/2049159988174602712" target="_blank" rel="noreferrer">Canonical</a>, and others all announced same-day availability. Key specs surfaced in follow-on posts: <a href="https://x.com/PiotrZelasko/status/2049162049599455725" target="_blank" rel="noreferrer">Piotr Żelasko</a> described it as NVIDIA’s first omni release with speech/audio understanding backed by a Parakeet encoder, English-only for now, and a 5.95% WER on the Open ASR leaderboard. Several hosts cited ~9× throughput versus comparable open omni models.</p><p>Other notable model/paper releases: <a href="https://x.com/kimmonismus/status/2049099376476459372" target="_blank" rel="noreferrer">Microsoft’s TRELLIS.2</a> is an open-source 4B image-to-3D model producing up to 1536³ PBR textured assets, built on native 3D VAEs with 16× spatial compression. On the world-model side, <a href="https://x.com/wjwang2003/status/2049136028968272260" target="_blank" rel="noreferrer">World-R1</a> claims existing video models already encode 3D structure and can be “woken up” with RL, requiring no architecture changes, no extra video training data, and no added inference cost.</p><p>Agents, Local-First Tooling, and Production Orchestration</p><p>Agent builders are shifting from demos to production primitives: <a href="https://x.com/MistralAI/status/2049128071874179091" target="_blank" rel="noreferrer">Mistral launched Workflows in public preview</a> as an orchestration layer aimed at turning enterprise AI processes into durable, observable, fault-tolerant production systems. Related posts echoed the same theme: <a href="https://x.com/sydneyrunkle/status/2049132897227936073" target="_blank" rel="noreferrer">Sydney Runkle framed durable execution</a> as a key requirement for long-running agents, and <a href="https://x.com/threepointone/status/2049088722835042475" target="_blank" rel="noreferrer">threepointone described work on subagents / agents-as-tools with persistence, streaming, and resumption</a>.</p><p>Local/offline agents moved from aspiration to credible workflow: <a href="https://x.com/Teknium/status/2048975223853350976" target="_blank" rel="noreferrer">Teknium asserted “totally offline agents are possible”</a>, while <a href="https://x.com/NielsRogge/status/2049128153658839324" target="_blank" rel="noreferrer">Niels Rogge demoed Pi + local models</a> for desktop cleanup and <a href="https://x.com/googlegemma/status/2049163687639007451" target="_blank" rel="noreferrer">Google Gemma shared a tutorial for local coding agents</a>. Hugging Face’s local push also showed up in adoption numbers: <a href="https://x.com/ClementDelangue/status/2049139562929143917" target="_blank" rel="noreferrer">Clement Delangue said 300,000 users have added hardware specs to the Hub</a> to discover what can run locally. Complementing this, <a href="https://x.com/ammaar/status/2049169134429073471" target="_blank" rel="noreferrer">Ammaar open-sourced a vibe-coding app running Gemma 4 fully on-device with MLX</a>, and <a href="https://x.com/kimmonismus/status/2049244932477759767" target="_blank" rel="noreferrer">Kimmonismus highlighted Sigma</a>, a private browser-based local-agent concept using open models.</p><p>Hermes and adjacent agent harnesses are gaining real-world traction: multiple posts reported Hermes outperforming OpenClaw in instruction-following or practical workflows, including <a href="https://x.com/SecretArjun/status/2049006382763110639" target="_blank" rel="noreferrer">SecretArjun</a>, <a href="https://x.com/somewheresy/status/2049089485938315614" target="_blank" rel="noreferrer">somewheresy</a>, and users deploying Hermes through <a href="https://x.com/lizliz404/status/2049084890717806877" target="_blank" rel="noreferrer">Telegram</a> or for <a href="https://x.com/bobvarkey/status/2049120693649125687" target="_blank" rel="noreferrer">medical literature extraction</a>. On the research-agent side, <a href="https://x.com/_lewtun/status/2049021398312468815" target="_blank" rel="noreferrer">Hugging Face’s ML Intern</a> was trending among Spaces, and later gained <a href="https://x.com/akseljoonas/status/2049183527703396699" target="_blank" rel="noreferrer">native metric logging + Trackio integration</a> to make its training jobs observable rather than black-box.</p><p>Benchmarks, Evals, and Research Findings Worth Watching</p><p>Model benchmarking remains fragmented, but a few signals stood out: <a href="https://x.com/EpochAIResearch/status/2049186851844771888" target="_blank" rel="noreferrer">Epoch reported GPT-5.5 Pro reaching </a><a href="https://x.com/EpochAIResearch/status/2049186851844771888" target="_blank" rel="noreferrer">159 on the Epoch Capabilities Index</a> and new highs on FrontierMath—52% on Tiers 1–3 and 40% on Tier 4—including two Tier 4 problems not previously solved by any model. Separately, <a href="https://x.com/GregKamradt/status/2049121093307547654" target="_blank" rel="noreferrer">Greg Kamradt said ARC-AGI-3 testing for GPT-5.5 and Opus 4.7 had completed</a>, with failure modes now under analysis.</p><p>Several new benchmarks target more realistic agent and engineering behavior: <a href="https://x.com/LysandreJik/status/2049053056814436352" target="_blank" rel="noreferrer">Lysandre announced a benchmark for making Transformers more agent-friendly</a>, and <a href="https://x.com/jpschroeder/status/2049139723776495800" target="_blank" rel="noreferrer">VibeBench</a> proposed subjective testing by 1,000 qualified software engineers to measure how models actually feel in real work. On document intelligence, <a href="https://x.com/llama_index/status/2049139409316946011" target="_blank" rel="noreferrer">LlamaIndex’s ParseBench</a> emphasized that OCR benchmarks miss semantic formatting such as strikethroughs and superscripts, which materially alter meaning for agents.</p><p>Research notes with concrete engineering implications: <a href="https://x.com/rosinality/status/2049024030749970699" target="_blank" rel="noreferrer">Rosinality flagged bugs in DeepSpeed and OpenRLHF that reduce SFT performance</a>, with implications for prior studies. <a href="https://x.com/arjunkocher/status/2049066844925936041" target="_blank" rel="noreferrer">Arjun Kocher published a faithful implementation of Compressed Sparse Attention from the DeepSeek-V4 paper</a>. <a href="https://x.com/che_shr_cat/status/2049081240762876261" target="_blank" rel="noreferrer">che_shr_cat showed single-block transformers can solve Extreme Sudoku only with an explicit scratchpad and inverted routing init</a>, otherwise performance is zero. On optimization, <a href="https://x.com/kellerjordan0/status/2049193527440187494" target="_blank" rel="noreferrer">Keller Jordan released a lightweight Modded-NanoGPT optimizer benchmark</a> designed to compare methods like Muon and AdamW on a reproducible speedrun-style task.</p><p>Platform Economics, API Pricing, and Closed-Model Reliability Concerns</p><p><a href="https://www.latent.space/p/ainews-not-much-happened-today" target="_blank" rel="noreferrer"> Read more </a></p><hr>',27)])])}const u=a(s,[["render",o]]);export{m as __pageData,u as default};
